function stripHtml(html) {
  if (!html) return '';
  return html
    .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
    .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ').replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<').replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"').replace(/&#39;/g, "'")
    .replace(/[ \t]+/g, ' ').replace(/\n{3,}/g, '\n\n').trim();
}
function fixMojibake(str) {
  if (!str || str.indexOf('\xc3') === -1) return str;
  try {
    var fixed = Buffer.from(str, 'latin1').toString('utf8');
    if (fixed.indexOf('\ufffd') === -1) return fixed;
  } catch(e) {}
  return str;
}
const emailItem = $input.all()[0];
const emailJson = emailItem.json;
const emailBinary = emailItem.binary || {};
const rawFrom = (emailJson.from || '').trim();
const bracketPos = rawFrom.indexOf('<');
const senderName = bracketPos > 0
  ? rawFrom.substring(0, bracketPos).split('"').join('').trim() || 'Unknown'
  : (rawFrom.replace(/<[^>]+>/g, '').trim() || 'Unknown');
const subject = (emailJson.subject || 'No Subject').trim();
const d = new Date(emailJson.date || Date.now());
const pad = function(n) { return String(n).padStart(2, '0'); };
const sentFm = pad(d.getDate()) + '.' + pad(d.getMonth()+1) + '.' + d.getFullYear() + ' ' + pad(d.getHours()) + '.' + pad(d.getMinutes()) + '.' + pad(d.getSeconds());
const datePrefix = d.getFullYear() + '-' + pad(d.getMonth()+1) + '-' + pad(d.getDate()) + ' ' + pad(d.getHours()) + '-' + pad(d.getMinutes());
const rawText = emailJson.text || emailJson.textPlain || emailJson.plain || '';
const rawHtml = emailJson.html || emailJson.textAsHtml || emailJson.htmlBody || '';
const bodyText = fixMojibake((rawText.trim() || stripHtml(rawHtml)).trim());
const safeSubject = subject.split('/').join('-').split('\\').join('-').split(':').join('-').split('*').join('-').split('?').join('-').split('<').join('-').split('>').join('-').split('|').join('-').substring(0, 80).trim();
const noteName = datePrefix + ' ' + safeSubject;
const notePath = '553 - emails/' + noteName + '.md';
const emailMeta = { senderName, subject, sentFm, bodyText, noteName, notePath };
const attachmentKeys = Object.keys(emailBinary).filter(function(k) { return k.startsWith('attachment'); });
if (attachmentKeys.length === 0) {
  return [{ json: Object.assign({}, emailMeta, { hasFile: false, attFilename: '', mediabankPath: '', attMimeType: '', attTotal: 0 }) }];
}
return attachmentKeys.map(function(key, i) {
  const att = emailBinary[key];
  const origName = att.fileName || att.filename || key;
  const dotPos = origName.lastIndexOf('.');
  const ext = dotPos >= 0 ? origName.substring(dotPos) : '';
  const attFilename = attachmentKeys.length === 1 ? noteName + ext : noteName + '-' + (i + 1) + ext;
  const mediabankPath = 'Mediabank/' + attFilename;
  return {
    json: Object.assign({}, emailMeta, {
      hasFile: true, attFilename, mediabankPath,
      attMimeType: att.mimeType || 'application/octet-stream',
      attTotal: attachmentKeys.length,
    }),
    binary: { file: att }
  };
});

const splitItems = $('Split Into Items').all();
return $input.all().map(function(item, i) {
  return {
    json: item.json,
    binary: splitItems[i] ? splitItems[i].binary : {}
  };
});

const items = $input.all();
const splitItems = $('Split Into Items').all();
const uploadItems = $('Upload to Mediabank').all();
return items.map(function(item, i) {
  const splitData = splitItems[i] ? splitItems[i].json : {};
  if (!splitData.hasFile) return { json: Object.assign({}, splitData, { attSection: '' }) };
  const convJson = item.json;
  const uploadJson = uploadItems[i] ? uploadItems[i].json : {};
  const uploadOk = !uploadJson.error && uploadJson.result === 'ok';
  const markdown = (!convJson.error && (convJson.markdown || '').trim()) || '*Conversion failed*';
  const embedLine = uploadOk ? '![[' + splitData.mediabankPath + ']]' : '*Mediabank save failed for ' + splitData.attFilename + '*';
  const attSection = '\n\n---\n\n## Attachment: ' + splitData.attFilename + '\n\n' + embedLine + '\n\n' + markdown;
  return { json: Object.assign({}, splitData, { attSection }) };
});

const items = $input.all();
const first = items[0].json;
const attSections = items.map(function(item) { return item.json.attSection || ''; }).filter(function(s) { return s.length > 0; });
return [{
  json: {
    senderName: first.senderName,
    subject: first.subject,
    sentFm: first.sentFm,
    bodyText: first.bodyText,
    noteName: first.noteName,
    notePath: first.notePath,
    attSections: attSections,
  }
}];

const agg = $('Aggregate Sections').first().json;
const ollamaResp = $input.first().json;
const rawKeyPoints = (ollamaResp.response || '').trim();
const keyPoints = agg.bodyText ? rawKeyPoints : '';
const fm = ['---', 'subject: ' + agg.subject, 'from: ' + agg.senderName, 'sent: ' + agg.sentFm, '---'].join('\n');
const keySection  = keyPoints    ? '\n\n### Key Points\n\n' + keyPoints     : '';
const bodySection = agg.bodyText ? '\n\n### Full Email\n\n' + agg.bodyText  : '';
const content = fm + '\n\nSend by [[' + agg.senderName + ']]' + keySection + bodySection + agg.attSections.join('');
const indexText = [keyPoints, agg.bodyText].filter(Boolean).join(' ') || agg.subject;
const attCount = agg.attSections.filter(function(s) { return s.length > 0; }).length;
const telegramLines = ['Email saved: <b>' + agg.noteName + '</b>', 'From: ' + agg.senderName];
if (attCount > 0) telegramLines.push('Attachments: ' + attCount);
telegramLines.push('Folder: 553 - emails');
return [{
  json: {
    noteBody:     JSON.stringify({ path: agg.notePath, content: content, overwrite: true }),
    indexBody:    JSON.stringify({ id: agg.notePath, text: indexText, collection: 'vault', metadata: { source: agg.notePath, type: 'email' } }),
    telegramText: telegramLines.join('\n'),
    noteName:     agg.noteName,
  }
}];
